contents.content:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Comic Sans MS', 'Chalkboard SE', cursive, sans-serif;
    background: linear-gradient(135deg, #f9d5e5 0%, #d5f0f9 100%);
    min-height: 100vh;
    padding: 30px 20px;
}

.container {
    max-width: 1200px;
    margin: 0 auto;
}

.header {
    text-align: center;
    margin-bottom: 40px;
    padding: 30px;
    background: white;
    border-radius: 60px 60px 30px 30px;
    box-shadow: 0 15px 30px rgba(0,0,0,0.15);
    border: 3px solid #ffb6c1;
    position: relative;
    overflow: hidden;
}

.header::before {
    content: "✨";
    font-size: 40px;
    position: absolute;
    left: 20px;
    top: 20px;
    opacity: 0.3;
}

.header::after {
    content: "📚";
    font-size: 40px;
    position: absolute;
    right: 20px;
    bottom: 20px;
    opacity: 0.3;
}

.header h1 {
    color: #ff6b6b;
    font-size: 3em;
    margin-bottom: 15px;
    text-shadow: 3px 3px 0 #ffeaa7;
}

.header p {
    color: #5f9ea0;
    font-size: 1.3em;
    margin-bottom: 20px;
}

.language-selector {
    margin: 20px auto;
    padding: 15px;
    background: #fff0f5;
    border-radius: 50px;
    display: inline-block;
    border: 2px dashed #ffb6c1;
}

.language-selector select {
    padding: 12px 25px;
    border-radius: 30px;
    border: 2px solid #ff9a9e;
    background: white;
    font-size: 1.1em;
    font-family: 'Comic Sans MS', cursive;
    cursor: pointer;
}

.stories-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 30px;
    margin-top: 40px;
}

.story-card {
    background: white;
    border-radius: 40px 20px 40px 20px;
    padding: 30px;
    box-shadow: 0 15px 25px rgba(0,0,0,0.1);
    transition: transform 0.3s ease;
    border: 3px solid #98ddca;
    position: relative;
}

.story-card:hover {
    transform: translateY(-10px);
}

.story-card h2 {
    color: #ff8a8a;
    font-size: 2em;
    margin-bottom: 15px;
    border-bottom: 3px dotted #a7e9af;
    padding-bottom: 10px;
}

.story-card p {
    color: #5d6d7e;
    font-size: 1.2em;
    line-height: 1.6;
    margin-bottom: 15px;
}

.story-card .animal-icon {
    font-size: 50px;
    text-align: right;
    margin-top: 10px;
}

.footer {
    text-align: center;
    margin-top: 60px;
    padding: 30px;
    background: white;
    border-radius: 30px 30px 60px 60px;
    border: 3px solid #ffb6c1;
    color: #5f9ea0;
    font-size: 1.2em;
}

const SITE_CODE = 'TINY-B86F5BD4';
const STORIES_NODE_CODE = 'STORIES-E77A07CB';
const API_URL = '$value(BASE_URL)';

function changeLanguage(lang) {
    const url = new URL(window.location.href);
    url.searchParams.set('translation', lang);
    window.location.href = url.toString();
}

async function fetchAllStories() {
    const url = `${API_URL}/contents/node/code/${STORIES_NODE_CODE}?status=SNAPSHOT`;
    try {
        const response = await fetch(url);
        if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
        return await response.json();
    } catch (error) {
        console.error('Error fetching stories:', error);
        return [];
    }
}

async function loadStoryContent(code, lang = 'en') {
    const url = `${API_URL}/contents/code/${code}?payloadOnly=true&status=SNAPSHOT&translation=${lang}`;
    try {
        const response = await fetch(url);
        if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
        const data = await response.json();

        // Si c'est un objet JSON, le retourner directement
        // Si c'est une chaîne JSON, la parser
        if (typeof data === 'object' && data !== null) {
            return data;
        }
        return typeof data === 'string' ? JSON.parse(data) : data;
    } catch (error) {
        console.error('Error fetching story:', error);
        return null;
    }
}

async function loadStories() {
    const storiesGrid = document.querySelector('.stories-grid');
    if (!storiesGrid) return;

    storiesGrid.innerHTML = '';

    const params = new URLSearchParams(window.location.search);
    const lang = params.get('translation') || 'en';

    // Récupérer tous les contenus du sous-nœud STORIES
    const allContents = await fetchAllStories();
    console.log('All contents from stories node:', allContents);

    // Filtrer uniquement les contenus de type JSON (les histoires)
    const stories = allContents.filter(content => content.type === 'JSON');
    console.log('Filtered JSON stories:', stories);

    const animalIcons = ['🐶', '🐱', '🦊', '🐼', '🐨', '🦁', '🐸', '🐧'];

    for (let i = 0; i < stories.length; i++) {
        const story = stories[i];
        const storyData = await loadStoryContent(story.code, lang);
        console.log('Story data for', story.code, ':', storyData);

        if (!storyData) continue;

        const card = document.createElement('div');
        card.className = 'story-card';

        const title = document.createElement('h2');
        title.textContent = storyData.title || 'A Tiny Tale';
        card.appendChild(title);

        if (storyData.content) {
            const content = document.createElement('p');
            content.textContent = storyData.content;
            card.appendChild(content);
        }

        const icon = document.createElement('div');
        icon.className = 'animal-icon';
        icon.textContent = animalIcons[i % animalIcons.length];
        card.appendChild(icon);

        storiesGrid.appendChild(card);
    }

    if (stories.length === 0) {
        storiesGrid.innerHTML = '<p style="text-align:center; font-size:1.5em;">✨ No stories yet, but check back soon! ✨</p>';
    }
}

window.addEventListener('load', function() {
    const params = new URLSearchParams(window.location.search);
    const lang = params.get('translation') || 'en';
    const select = document.querySelector('select');
    if (select) select.value = lang;
    loadStories();
});
